            <label class="settings-switch">
              <input type="checkbox" id="auto-collapse-toggle" checked />
              <span class="settings-slider"></span>
            </label>
          </div>
          <div class="text-xs text-gray-500 mt-1">开启时默认折叠角色状态详情，关闭时默认展开</div>
